581→void ALFPHexGridManager::DrawDebugPath(const TArray<ALFPHexTile*>& Path, bool bPathFound)
582→{
583→	if (!GetWorld()) return;
584→
585→	const float DebugDuration = 5.0f; // 显示5秒
586→
587→	// 绘制起点和终点
588→	if (Path.Num() > 0) {
589→		// 起点：绿色球体
590→		DrawDebugSphere(
591→			GetWorld(),
592→			Path[0]->GetActorLocation() + FVector(0, 0, 20),
593→			15.0f, 12, FColor::Green, false, DebugDuration
594→		);
595→	}
596→
597→	if (bPathFound && Path.Num() > 1) {
598→		// 终点：蓝色球体
599→		DrawDebugSphere(
600→			GetWorld(),
601→			Path.Last()->GetActorLocation() + FVector(0, 0, 20),
602→			15.0f, 12, FColor::Blue, false, DebugDuration
603→		);
604→	}
605→
606→	// 绘制路径线段
607→	for (int32 i = 0; i < Path.Num() - 1; i++)
608→	{
609→		FVector StartLoc = Path[i]->GetActorLocation() + FVector(0, 0, 15);
610→		FVector EndLoc = Path[i + 1]->GetActorLocation() + FVector(0, 0, 15);
611→
612→		// 路径线：黄色
613→		DrawDebugLine(
614→			GetWorld(),
615→			StartLoc,
616→			EndLoc,
617→			FColor::Yellow,
618→			false,
619→			DebugDuration,
620→			0,
621→			3.0f // 线宽
622→		);
623→
624→		// 路径点：黄色球体
625→		DrawDebugSphere(
626→			GetWorld(),
627→			StartLoc,
628→			10.0f, 8, FColor::Yellow, false, DebugDuration
629→		);
630→	}
631→
632→	// 如果找到路径（但前面已经绘制过了，比如长度为1时）
633→	if (bPathFound && Path.Num() == 1) {
634→		DrawDebugSphere(
635→			GetWorld(),
636→			Path[0]->GetActorLocation() + FVector(0, 0, 20),
637→			15.0f, 12, FColor::Blue, false, DebugDuration
638→		);
639→	}
640→
641→	// 寻路失败提示
642→	if (!bPathFound) {
643→		// 在起始位置绘制红色X
644→		FVector StartLoc = Path.Num() > 0 ?
645→			Path[0]->GetActorLocation() :
646→			(GetActorLocation() + FVector(0, 0, 100));
647→
648→		DrawDebugLine(
649→			GetWorld(),
650→			StartLoc + FVector(-30, -30, 50),
651→			StartLoc + FVector(30, 30, 50),
652→			FColor::Red, false, DebugDuration, 0, 5.0f
653→		);
654→		DrawDebugLine(
655→			GetWorld(),
656→			StartLoc + FVector(-30, 30, 50),
657→			StartLoc + FVector(30, -30, 50),
658→			FColor::Red, false, DebugDuration, 0, 5.0f
659→		);
660→	}
661→}
