716→// 像素位置转换为六边形坐标
717→FLFPHexCoordinates ALFPHexGridManager::PixelToHexCoordinates(const FVector2D& PixelPosition, float InHexSize)
718→{
719→    // 获取像素值
720→    float x = PixelPosition.X;
721→    float y = PixelPosition.Y;
722→
723→    // 转换为立方坐标 - 尖顶六边形公式
724→    float q = (2.0f / 3.0f) * x;
725→    float r = (-1.0f / 3.0f) * x + (FMath::Sqrt(3.0f) / 3.0f) * y;
726→
727→    // 使用优化后的四舍五入到最近坐标
728→    return RoundToHex(q, r);
729→}
