836→// 优化后的四舍五入到最近六边形坐标
837→FLFPHexCoordinates ALFPHexGridManager::RoundToHex(float q, float r)
838→{
839→	// 转换为立方坐标
840→	float cube_x = q;
841→	float cube_z = r;
842→	float cube_y = -cube_x - cube_z;
843→
844→	// 分别四舍五入到最近整数
845→	int32 rx = FMath::RoundToInt(cube_x);
846→	int32 ry = FMath::RoundToInt(cube_y);
847→	int32 rz = FMath::RoundToInt(cube_z);
848→
849→	// 计算四舍五入误差
850→	float x_diff = FMath::Abs(rx - cube_x);
851→	float y_diff = FMath::Abs(ry - cube_y);
852→	float z_diff = FMath::Abs(rz - cube_z);
853→
854→	// 修正最大误差的分量
855→	if (x_diff > y_diff && x_diff > z_diff) {
856→		rx = -ry - rz;
857→	}
858→	else if (y_diff > z_diff) {
859→		ry = -rx - rz;
860→	}
861→	else {
862→		rz = -rx - ry;
863→	}
864→
865→	return FLFPHexCoordinates(rx, rz);
866→}
