 325→void ALFPTacticsPlayerController::OnConfirmAction(const FInputActionValue& Value)
 326→{
 327→    if (bWaitingForMove) return;
 328→    bIsDragging = false;
 329→    if (DragTime > DragThresholdTime)
 330→    {
 331→        DragTime = 0.f;
 332→        return;
 333→    }
 334→    DragTime = 0.f;
 335→
 336→    // 布置阶段优先处理
 337→    if (bIsInDeployment)
 338→    {
 339→        if (bIsPlacingUnit)
 340→        {
 341→            // 正在放置单位：检测是否点击了空闲出生点
 342→            if (LastHoveredTile && PlayerSpawnTiles.Contains(LastHoveredTile)
 343→                && !LastHoveredTile->IsOccupied())
 344→            {
 345→                PlaceUnit(LastHoveredTile);
 346→            }
 347→        }
 348→        else
 349→        {
 350→            // 不在放置模式：检测是否点击了已放置的单位（拾起）
 351→            FHitResult HitResult;
 352→            GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
 353→            ALFPTacticsUnit* ClickedUnit = Cast<ALFPTacticsUnit>(HitResult.GetActor());
 354→            if (ClickedUnit && DeployedUnits.Contains(ClickedUnit))
 355→            {
 356→                PickupDeployedUnit(ClickedUnit);
 357→            }
 358→        }
 359→        return;
 360→    }
 361→
 362→    // 编辑器模式优先处理
 363→    if (MapEditorComponent && MapEditorComponent->IsEditorActive())
 364→    {
 365→        if (LastHoveredTile)
 366→        {
 367→            MapEditorComponent->ApplyToolToTile(LastHoveredTile);
 368→        }
 369→        else if (GridManager && MapEditorComponent->GetCurrentTool() == ELFPMapEditorTool::MET_AddTile)
 370→        {
 371→            // 对空白区域添加格子：射线投射到 Z=0 平面计算坐标
 372→            FVector WorldOrigin, WorldDirection;
 373→            DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
 374→            if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
 375→            {
 376→                float T = -WorldOrigin.Z / WorldDirection.Z;
 377→                FVector HitPoint = WorldOrigin + WorldDirection * T;
 378→                FVector2D LocalLoc(
 379→                    HitPoint.X - GridManager->GetActorLocation().X,
 380→                    HitPoint.Y - GridManager->GetActorLocation().Y
 381→                );
 382→                FLFPHexCoordinates Coord = FLFPHexCoordinates::FromWorldLocation(
 383→                    LocalLoc, GridManager->GetHexSize(), GridManager->GetVerticalScale());
 384→                MapEditorComponent->ApplyToolToCoord(Coord.Q, Coord.R);
 385→            }
 386→        }
 387→        return;
 388→    }
 389→
 390→    if (SelectedUnit && SelectedTile)
 391→    {
 392→        if (bIsAttacking)
 393→        {
 394→            // 获取鼠标位置
 395→            float MouseX, MouseY;
 396→            GetMousePosition(MouseX, MouseY);
 397→            FVector2D SelectionEnd = FVector2D(MouseX, MouseY);
 398→
 399→            FHitResult HitResult;
 400→            GetHitResultAtScreenPosition(SelectionEnd, ECC_Visibility, false, HitResult);
 401→
 402→            if (HitResult.bBlockingHit)
 403→            {
 404→                // 尝试选中单位
 405→                ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(HitResult.GetActor());
 406→                if (Unit)
 407→                {
 408→                    AttackTarget(SelectedUnit, Unit);
 409→                    return;
 410→                }
 411→            }
 412→        }
 413→        else if (bIsReleaseSkill && CurrentSelectedSkill)
 414→        {
 415→            ExecuteSkill(CurrentSelectedSkill);
 416→        }
 417→        else
 418→        {
 419→            ConfirmMove();
 420→        }
 421→    }
 422→    else if (SelectedUnit)
 423→    {
 424→        // 如果没有选中目标格子，显示可移动范围
 425→        //ShowMovementRange(true);
 426→    }
 427→}
