1069→void ALFPTacticsPlayerController::StartPlacingUnit(int32 PartyIndex)
1070→{
1071→    // 如果正在放置其他单位，先取消
1072→    if (bIsPlacingUnit)
1073→    {
1074→        CancelPlacing();
1075→    }
1076→
1077→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
1078→    if (!GI || !GI->UnitRegistry) return;
1079→    if (!GI->PartyUnits.IsValidIndex(PartyIndex)) return;
1080→
1081→    // 如果该单位已经放置，先拾起
1082→    if (DeployedUnits.IsValidIndex(PartyIndex) && DeployedUnits[PartyIndex])
1083→    {
1084→        PickupDeployedUnit(DeployedUnits[PartyIndex]);
1085→    }
1086→
1087→    const FLFPUnitEntry& Entry = GI->PartyUnits[PartyIndex];
1088→    TSubclassOf<ALFPTacticsUnit> UnitClass = GI->UnitRegistry->GetUnitClass(Entry.TypeID);
1089→    if (!UnitClass) return;
1090→
1091→    // 在鼠标位置生成预览单位
1092→    FVector UnitSpawnLoc = FVector(0, 0, 50.f);
1093→    FActorSpawnParameters SpawnParams;
1094→    PlacingUnitPreview = GetWorld()->SpawnActor<ALFPTacticsUnit>(UnitClass, UnitSpawnLoc, FRotator::ZeroRotator, SpawnParams);
1095→
1096→    if (PlacingUnitPreview)
1097→    {
1098→        PlacingUnitPreview->Affiliation = EUnitAffiliation::UA_Player;
1099→        PlacingUnitPreview->UnitTypeID = Entry.TypeID;
1100→        PlacingUnitPreview->UnitTier = Entry.Tier;
1101→    }
1102→
1103→    PlacingPartyIndex = PartyIndex;
1104→    bIsPlacingUnit = true;
1105→
1106→    if (DeploymentWidget)
1107→    {
1108→        DeploymentWidget->MarkUnitSelecting(PartyIndex);
1109→    }
1110→
1111→    UE_LOG(LogTemp, Log, TEXT("开始放置单位 %s（索引 %d）"), *Entry.TypeID.ToString(), PartyIndex);
1112→}
