1159→void ALFPTacticsPlayerController::PickupDeployedUnit(ALFPTacticsUnit* Unit)
1160→{
1161→    if (!Unit) return;
1162→
1163→    // 找到对应的 PartyIndex
1164→    int32 FoundIndex = DeployedUnits.Find(Unit);
1165→    if (FoundIndex == INDEX_NONE) return;
1166→
1167→    // 清除格子占用
1168→    ALFPHexTile* OldTile = Unit->GetCurrentTile();
1169→    if (OldTile)
1170→    {
1171→        OldTile->SetIsOccupied(false);
1172→        OldTile->SetUnitOnTile(nullptr);
1173→    }
1174→
1175→    // 设置为跟随鼠标的预览
1176→    PlacingUnitPreview = Unit;
1177→    PlacingPartyIndex = FoundIndex;
1178→    bIsPlacingUnit = true;
1179→
1180→    // 清除已布置记录
1181→    DeployedUnits[FoundIndex] = nullptr;
1182→
1183→    // 更新 UI
1184→    if (DeploymentWidget)
1185→    {
1186→        DeploymentWidget->MarkUnitPlaced(FoundIndex, false);
1187→    }
1188→
1189→    UE_LOG(LogTemp, Log, TEXT("拾起已放置的单位（索引 %d）"), FoundIndex);
1190→}
